function render() {
  const m = appsmith.model || {};
  const titleEl = document.getElementById('navTitle');
  const subtitleEl = document.getElementById('navSubtitle');
  const badgeTextEl = document.getElementById('badgeText');
  if (titleEl) titleEl.textContent = m.title || '';
  if (subtitleEl) subtitleEl.textContent = m.subtitle || '';
  if (badgeTextEl) badgeTextEl.textContent = m.badge || 'OPC';
  const roleBadgeEl = document.getElementById('userRoleBadge');
  if (roleBadgeEl && m.role) {
    roleBadgeEl.textContent = m.role;
    roleBadgeEl.style.display = 'inline-block';
  }
  const switchBtnEl = document.getElementById('btnSwitchClient');
  const switchLabelEl = document.getElementById('switchClientLabel');
  const clients = m.clients || [];
  if (switchBtnEl && clients.length === 2 && m.currentClient) {
    const otherClient = clients.find(function (c) {
      return c !== m.currentClient;
    });
    if (switchLabelEl) switchLabelEl.textContent = 'Switch to ' + otherClient;
    switchBtnEl.style.display = 'inline-flex';
    switchBtnEl.onclick = function () {
      appsmith.updateModel({
        switchToClient: otherClient
      });
      appsmith.triggerEvent('onSwitchClient');
    };
  } else if (switchBtnEl) {
    switchBtnEl.style.display = 'none';
  }
  const itemsEl = document.getElementById('navItems');
  if (!itemsEl) return;
  itemsEl.innerHTML = '';
  const navItems = m.navItems || [];
  const allowedRoles = m.allowedRestrictedRoles || [];
  const currentRole = m.role;
  navItems.forEach(function (item) {
    if (item.restricted && !allowedRoles.includes(currentRole)) {
      return;
    }
    const btn = document.createElement('button');
    const isActive = item.page === m.activePage;
    btn.className = 'nav-btn' + (isActive ? ' active' : '');
    let btnHTML = '';
    if (item.icon) {
      btnHTML += `<span class="nav-icon">${item.icon}</span>`;
    }
    btnHTML += `<span>${item.label}</span>`;
    btn.innerHTML = btnHTML;
    if (isActive) {
      setTimeout(() => {
        btn.scrollIntoView({
          behavior: 'smooth',
          block: 'nearest',
          inline: 'center'
        });
      }, 100);
    }
    btn.onclick = function () {
      appsmith.updateModel({
        navigateTo: item.page
      });
      appsmith.triggerEvent('onNavigate');
    };
    itemsEl.appendChild(btn);
  });
}
appsmith.onReady(function () {
  render();
  const btnLogout = document.getElementById('btnLogout');
  if (btnLogout) {
    btnLogout.onclick = function () {
      appsmith.triggerEvent('onLogout');
    };
  }
});
appsmith.onModelChange(function () {
  render();
});

